INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("物理防御力（ダウン不可）アップ", "バトル開始時、すべてのモンスターの物理防御力を大アップさせる。この効果は物理防御力ダウンの影響を受けない。", 4100310, 10031003, "boss_def_lower_limit");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("魔法防御力（ダウン不可）アップ", "バトル開始時、すべてのモンスターの魔法防御力を大アップさせる。この効果は魔法防御力ダウンの影響を受けない。", 4100310, 10031004, "boss_magic_def_lower_limit");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰダウンカット", "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。", 4100310, 10031005, "boss_tp_down_cut");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰ上昇ダウン", "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", 4100310, 10031006, 3);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＨＰ吸収ダウン", "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", 4100310, 10031007, 9);
